        impl Parse for ExprIf {
            fn parse(input: ParseStream) -> Result<Self> {
                let attrs = input.call(Attribute::parse_outer)?;
                let mut clauses = Vec::new();
                let mut expr;
                loop {
                    let if_token: crate::token::If = input.parse()?;
                    let cond = input.call(Expr::parse_without_eager_brace)?;
                    let then_branch: Block = input.parse()?;
                    expr = ExprIf {
                        attrs: Vec::new(),
                        if_token,
                        cond: Box::new(cond),
                        then_branch,
                        else_branch: None,
                    };
                    if !input.peek(crate::token::Else) {
                        break;
                    }
                    let else_token: crate::token::Else = input.parse()?;
                    let lookahead = input.lookahead1();
                    if lookahead.peek(crate::token::If) {
                        expr.else_branch = Some((
                            else_token,
                            Box::new(Expr::PLACEHOLDER),
                        ));
                        clauses.push(expr);
                    } else if lookahead.peek(token::Brace) {
                        expr.else_branch = Some((
                            else_token,
                            Box::new(
                                Expr::Block(ExprBlock {
                                    attrs: Vec::new(),
                                    label: None,
                                    block: input.parse()?,
                                }),
                            ),
                        ));
                        break;
                    } else {
                        return Err(lookahead.error());
                    }
                }
                while let Some(mut prev) = clauses.pop() {
                    *prev.else_branch.as_mut().unwrap().1 = Expr::If(expr);
                    expr = prev;
                }
                expr.attrs = attrs;
                Ok(expr)
            }
        }
