        fn expr_break(
            input: ParseStream,
            allow_struct: AllowStruct,
        ) -> Result<ExprBreak> {
            let break_token: crate::token::Break = input.parse()?;
            let ahead = input.fork();
            let label: Option<Lifetime> = ahead.parse()?;
            if label.is_some() && ahead.peek(crate::token::Colon) {
                let _: Expr = input.parse()?;
                let start_span = label.unwrap().apostrophe;
                let end_span = input.cursor().prev_span();
                return Err(
                    crate::error::new2(start_span, end_span, "parentheses required"),
                );
            }
            input.advance_to(&ahead);
            let expr = if Expr::peek(input)
                && (allow_struct.0 || !input.peek(token::Brace))
            {
                Some(input.parse()?)
            } else {
                None
            };
            Ok(ExprBreak {
                attrs: Vec::new(),
                break_token,
                label,
                expr,
            })
        }
