                    let has_body = input.peek(token::Brace);
                    let semi_token: Option<crate::token::Semi> = if has_body {
                        let content;
                        match crate::__private::parse_braces(&input) {
                            crate::__private::Ok(braces) => {
                                content = braces.content;
                                _ = content;
                                braces.token
                            }
                            crate::__private::Err(error) => {
                                return crate::__private::Err(error);
                            }
                        };
                        content.call(Attribute::parse_inner)?;
                        content.call(Block::parse_within)?;
                        None
                    } else {
                        Some(input.parse()?)
                    };
                    if has_safe || has_body {
                        Ok(ForeignItem::Verbatim(verbatim::between(&begin, input)))
                    } else {
                        Ok(
                            ForeignItem::Fn(ForeignItemFn {
                                attrs: Vec::new(),
                                vis,
                                sig: sig.unwrap(),
                                semi_token: semi_token.unwrap(),
                            }),
                        )
                    }
