        fn parse_rest_of_trait_alias(
            input: ParseStream,
            attrs: Vec<Attribute>,
            vis: Visibility,
            trait_token: crate::token::Trait,
            ident: Ident,
            mut generics: Generics,
        ) -> Result<ItemTraitAlias> {
            let eq_token: crate::token::Eq = input.parse()?;
            let mut bounds = Punctuated::new();
            loop {
                if input.peek(crate::token::Where) || input.peek(crate::token::Semi) {
                    break;
                }
                bounds
                    .push_value({
                        let allow_precise_capture = false;
                        let allow_const = false;
                        TypeParamBound::parse_single(
                            input,
                            allow_precise_capture,
                            allow_const,
                        )?
                    });
                if input.peek(crate::token::Where) || input.peek(crate::token::Semi) {
                    break;
                }
                bounds.push_punct(input.parse()?);
            }
            generics.where_clause = input.parse()?;
            let semi_token: crate::token::Semi = input.parse()?;
            Ok(ItemTraitAlias {
                attrs,
                vis,
                trait_token,
                ident,
                generics,
                eq_token,
                bounds,
                semi_token,
            })
        }
