    /// use syn::{parse_macro_input, LitStr, Path};
    ///
    /// # const IGNORE: &str = stringify! {
    /// #[proc_macro_attribute]
    /// # };
    /// pub fn tea(args: TokenStream, input: TokenStream) -> TokenStream {
