        ///     attr.parse_nested_meta(|meta| {      // this parses the `(`
        ///         if meta.path.is_ident("kind") {  // this parses the `kind`
        ///             let value = meta.value()?;   // this parses the `=`
        ///             let s: LitStr = value.parse()?;  // this parses `"EarlGrey"`
