    pub trait ParseQuote: Sized {
        fn parse(input: ParseStream) -> Result<Self>;
    }
    impl<T: Parse> ParseQuote for T {
        fn parse(input: ParseStream) -> Result<Self> {
            <T as Parse>::parse(input)
        }
    }
    use crate::punctuated::Punctuated;
    use crate::{attr, Attribute, Field, FieldMutability, Ident, Type, Visibility};
    use crate::{Arm, Block, Pat, Stmt};
    impl ParseQuote for Attribute {
        fn parse(input: ParseStream) -> Result<Self> {
            if input.peek(crate::token::Pound) && input.peek2(crate::token::Not) {
                attr::parsing::single_parse_inner(input)
            } else {
                attr::parsing::single_parse_outer(input)
            }
        }
    }
    impl ParseQuote for Vec<Attribute> {
        fn parse(input: ParseStream) -> Result<Self> {
            let mut attrs = Vec::new();
            while !input.is_empty() {
                attrs.push(ParseQuote::parse(input)?);
            }
            Ok(attrs)
        }
    }
    impl ParseQuote for Field {
        fn parse(input: ParseStream) -> Result<Self> {
            let attrs = input.call(Attribute::parse_outer)?;
            let vis: Visibility = input.parse()?;
            let ident: Option<Ident>;
            let colon_token: Option<crate::token::Colon>;
            let is_named = input.peek(Ident) && input.peek2(crate::token::Colon)
                && !input.peek2(crate::token::PathSep);
            if is_named {
                ident = Some(input.parse()?);
                colon_token = Some(input.parse()?);
            } else {
                ident = None;
                colon_token = None;
            }
            let ty: Type = input.parse()?;
            Ok(Field {
                attrs,
                vis,
                mutability: FieldMutability::None,
                ident,
                colon_token,
                ty,
            })
        }
    }
