mod verbatim {
    use crate::ext::TokenStreamExt as _;
    use crate::parse::ParseStream;
    use core::cmp::Ordering;
    use proc_macro2::{Delimiter, TokenStream};
    pub(crate) fn between<'a>(
        begin: ParseStream<'a>,
        end: ParseStream<'a>,
    ) -> TokenStream {
        let end = end.cursor();
        let mut cursor = begin.cursor();
        if !crate::buffer::same_buffer(end, cursor) {
            ::core::panicking::panic(
                "assertion failed: crate::buffer::same_buffer(end, cursor)",
            )
        }
        let mut tokens = TokenStream::new();
        while cursor != end {
            let (tt, next) = cursor.token_tree().unwrap();
            if crate::buffer::cmp_assuming_same_buffer(end, next) == Ordering::Less {
                if let Some((inside, _span, after)) = cursor.group(Delimiter::None) {
                    if !(next == after) {
                        ::core::panicking::panic("assertion failed: next == after")
                    }
                    cursor = inside;
                    continue;
                } else {
                    {
                        ::core::panicking::panic_fmt(
                            format_args!(
                                "verbatim end must not be inside a delimited group",
                            ),
                        );
                    };
                }
            }
            tokens.append(tt);
            cursor = next;
        }
        tokens
    }
}
mod whitespace {
    pub(crate) fn skip(mut s: &str) -> &str {
        'skip: while !s.is_empty() {
            let byte = s.as_bytes()[0];
            if byte == b'/' {
                if s.starts_with("//")
                    && (!s.starts_with("///") || s.starts_with("////"))
                    && !s.starts_with("//!")
                {
                    if let Some(i) = s.find('\n') {
                        s = &s[i + 1..];
                        continue;
                    } else {
                        return "";
                    }
                } else if s.starts_with("/**/") {
                    s = &s[4..];
                    continue;
                } else if s.starts_with("/*")
                    && (!s.starts_with("/**") || s.starts_with("/***"))
                    && !s.starts_with("/*!")
                {
                    let mut depth = 0;
                    let bytes = s.as_bytes();
                    let mut i = 0;
                    let upper = bytes.len() - 1;
                    while i < upper {
                        if bytes[i] == b'/' && bytes[i + 1] == b'*' {
                            depth += 1;
                            i += 1;
                        } else if bytes[i] == b'*' && bytes[i + 1] == b'/' {
                            depth -= 1;
                            if depth == 0 {
                                s = &s[i + 2..];
                                continue 'skip;
                            }
                            i += 1;
                        }
                        i += 1;
                    }
                    return s;
                }
            }
            match byte {
                b' ' | 0x09..=0x0D => {
                    s = &s[1..];
                    continue;
                }
                b if b <= 0x7F => {}
                _ => {
                    let ch = s.chars().next().unwrap();
                    if is_whitespace(ch) {
                        s = &s[ch.len_utf8()..];
                        continue;
                    }
                }
            }
            return s;
        }
        s
    }
    fn is_whitespace(ch: char) -> bool {
        ch.is_whitespace() || ch == '\u{200e}' || ch == '\u{200f}'
    }
}
